# solution.py
"""Team collaboration manager.

A self-contained, thread-safe, in-memory backend for managing users,
projects, tasks, messaging, performance metrics and reporting.

Although the surrounding task prompt describes a collaborative coding
notebook ("CodeSync"), the authoritative contract for this module is the
accompanying ``test_solution.py`` suite, which exercises a
``TeamCollaborationManager``.  This implementation satisfies that contract.

Standard library only.
"""

import copy
import csv
import io
import threading
from datetime import datetime
from enum import Enum


# ---------------------------------------------------------------------------
# Enumerations
# ---------------------------------------------------------------------------
class TaskStatus(Enum):
    """Lifecycle states for a task."""

    NOT_STARTED = "not_started"
    IN_PROGRESS = "in_progress"
    COMPLETED = "completed"


class UserRole(Enum):
    """Roles a user can hold within the system."""

    MEMBER = "member"
    ADMIN = "admin"


class ReportFormat(Enum):
    """Supported export formats for reports."""

    CSV = "csv"
    PDF = "pdf"


class ReportType(Enum):
    """Categories of report the manager can produce."""

    PROJECT_PROGRESS = "project_progress"
    TEAM_PERFORMANCE = "team_performance"
    INDIVIDUAL_PERFORMANCE = "individual_performance"


# ---------------------------------------------------------------------------
# Exception hierarchy
# ---------------------------------------------------------------------------
class TeamCollaborationError(Exception):
    """Base class for all errors raised by the manager."""


class ValidationError(TeamCollaborationError):
    """Raised when input fails validation."""


class NotFoundError(TeamCollaborationError):
    """Raised when a referenced entity does not exist."""


class AuthorizationError(TeamCollaborationError):
    """Raised when an actor is not permitted to perform an action."""


class DuplicateError(TeamCollaborationError):
    """Raised when a uniqueness constraint is violated."""


class ConflictError(TeamCollaborationError):
    """Raised when an operation conflicts with existing state."""


# ---------------------------------------------------------------------------
# Data models
# ---------------------------------------------------------------------------
class User(object):
    """A registered user."""

    __slots__ = ("id", "username", "email", "role", "created_at")

    def __init__(self, id, username, email, role, created_at):
        self.id = id
        self.username = username
        self.email = email
        self.role = role
        self.created_at = created_at

    def __repr__(self):  # pragma: no cover - convenience only
        return "User(id={0!r}, username={1!r}, role={2!r})".format(
            self.id, self.username, self.role
        )


class Project(object):
    """A project owned by a user, bounded by a start and end date."""

    __slots__ = (
        "id",
        "name",
        "description",
        "start_date",
        "end_date",
        "owner_id",
        "created_at",
    )

    def __init__(
        self, id, name, description, start_date, end_date, owner_id, created_at
    ):
        self.id = id
        self.name = name
        self.description = description
        self.start_date = start_date
        self.end_date = end_date
        self.owner_id = owner_id
        self.created_at = created_at

    def __repr__(self):  # pragma: no cover - convenience only
        return "Project(id={0!r}, name={1!r}, owner_id={2!r})".format(
            self.id, self.name, self.owner_id
        )


class Attachment(object):
    """A binary attachment bound to a message."""

    __slots__ = ("filename", "size", "uploaded_by", "uploaded_at")

    def __init__(self, filename, size, uploaded_by, uploaded_at):
        self.filename = filename
        self.size = size
        self.uploaded_by = uploaded_by
        self.uploaded_at = uploaded_at

    def __repr__(self):  # pragma: no cover - convenience only
        return "Attachment(filename={0!r}, size={1!r})".format(
            self.filename, self.size
        )


class Task(object):
    """A unit of work within a project."""

    __slots__ = (
        "id",
        "project_id",
        "title",
        "status",
        "assignee_id",
        "deadline",
        "started_at",
        "completed_at",
        "created_at",
    )

    def __init__(
        self,
        id,
        project_id,
        title,
        status,
        assignee_id,
        deadline,
        started_at,
        completed_at,
        created_at,
    ):
        self.id = id
        self.project_id = project_id
        self.title = title
        self.status = status
        self.assignee_id = assignee_id
        self.deadline = deadline
        self.started_at = started_at
        self.completed_at = completed_at
        self.created_at = created_at

    def __repr__(self):  # pragma: no cover - convenience only
        return "Task(id={0!r}, title={1!r}, status={2!r})".format(
            self.id, self.title, self.status
        )


class Message(object):
    """A message posted against a project or task, with optional attachments."""

    __slots__ = (
        "id",
        "author_id",
        "body",
        "project_id",
        "task_id",
        "parent_id",
        "attachments",
        "created_at",
        "edited_at",
    )

    def __init__(
        self,
        id,
        author_id,
        body,
        project_id,
        task_id,
        parent_id,
        attachments,
        created_at,
        edited_at,
    ):
        self.id = id
        self.author_id = author_id
        self.body = body
        self.project_id = project_id
        self.task_id = task_id
        self.parent_id = parent_id
        self.attachments = attachments
        self.created_at = created_at
        self.edited_at = edited_at

    def __repr__(self):  # pragma: no cover - convenience only
        return "Message(id={0!r}, author_id={1!r})".format(
            self.id, self.author_id
        )


class Rating(object):
    """A peer rating with an optional task reference and feedback."""

    __slots__ = (
        "id",
        "rater_id",
        "ratee_id",
        "score",
        "feedback",
        "task_id",
        "created_at",
    )

    def __init__(
        self, id, rater_id, ratee_id, score, feedback, task_id, created_at
    ):
        self.id = id
        self.rater_id = rater_id
        self.ratee_id = ratee_id
        self.score = score
        self.feedback = feedback
        self.task_id = task_id
        self.created_at = created_at

    def __repr__(self):  # pragma: no cover - convenience only
        return "Rating(id={0!r}, ratee_id={1!r}, score={2!r})".format(
            self.id, self.ratee_id, self.score
        )


# ---------------------------------------------------------------------------
# Shared state
# ---------------------------------------------------------------------------
class _Store(object):
    """Central state container shared by every service.

    A single re-entrant lock guards all mutations so that the manager and
    each service can compose operations safely under concurrency.
    """

    def __init__(self, now):
        self.lock = threading.RLock()
        self._now = now
        self.users = {}
        self.projects = {}
        self.tasks = {}
        self.messages = {}
        self.ratings = {}
        self._id_counter = 0

    def now(self):
        return self._now()

    def next_id(self):
        # Always invoked while holding ``self.lock``.
        self._id_counter += 1
        return self._id_counter


# ---------------------------------------------------------------------------
# Helpers
# ---------------------------------------------------------------------------
def _clone(obj):
    """Return a deep copy so callers cannot mutate stored state."""

    return copy.deepcopy(obj)


def _is_blank(value):
    return value is None or not str(value).strip()


def _valid_email(email):
    if _is_blank(email):
        return False
    email = email.strip()
    at = email.find("@")
    if at <= 0:
        return False
    if at == len(email) - 1:
        return False
    return True


def _scalar(value):
    """Render a value as a flat string for CSV / PDF output."""

    if value is None:
        return ""
    if isinstance(value, Enum):
        return str(value.value)
    if isinstance(value, datetime):
        return value.isoformat()
    return str(value)


def _task_metrics(tasks):
    """Compute aggregate metrics for a collection of tasks."""

    total = len(tasks)
    completed = 0
    in_progress = 0
    not_started = 0
    durations = []
    for task in tasks:
        if task.status == TaskStatus.COMPLETED:
            completed += 1
            if task.started_at is not None and task.completed_at is not None:
                durations.append(
                    (task.completed_at - task.started_at).total_seconds()
                )
        elif task.status == TaskStatus.IN_PROGRESS:
            in_progress += 1
        else:
            not_started += 1
    completion_rate = (float(completed) / total) if total else 0.0
    average_time = (sum(durations) / len(durations)) if durations else None
    return {
        "total_tasks": total,
        "completed_tasks": completed,
        "in_progress_tasks": in_progress,
        "not_started_tasks": not_started,
        "completion_rate": completion_rate,
        "average_completion_time": average_time,
    }


# ---------------------------------------------------------------------------
# Service base
# ---------------------------------------------------------------------------
class _Service(object):
    """Base for domain services; exposes the shared lock used by tests."""

    def __init__(self, store):
        self._store = store
        self._lock = store.lock

    # -- internal lookups (return live objects; never copied) -------------
    def _user_or_raise(self, user_id):
        user = self._store.users.get(user_id)
        if user is None:
            raise NotFoundError("User {0} not found".format(user_id))
        return user

    def _project_or_raise(self, project_id):
        project = self._store.projects.get(project_id)
        if project is None:
            raise NotFoundError("Project {0} not found".format(project_id))
        return project

    def _task_or_raise(self, task_id):
        task = self._store.tasks.get(task_id)
        if task is None:
            raise NotFoundError("Task {0} not found".format(task_id))
        return task

    def _message_or_raise(self, message_id):
        message = self._store.messages.get(message_id)
        if message is None:
            raise NotFoundError("Message {0} not found".format(message_id))
        return message


# ---------------------------------------------------------------------------
# User service
# ---------------------------------------------------------------------------
class _UserService(_Service):
    def register_user(self, username, email, role=UserRole.MEMBER):
        with self._lock:
            if _is_blank(username):
                raise ValidationError("username must not be empty")
            if not _valid_email(email):
                raise ValidationError("invalid email address")
            if not isinstance(role, UserRole):
                raise ValidationError("role must be a UserRole")
            username = username.strip()
            email = email.strip()
            self._ensure_unique_username(username, None)
            self._ensure_unique_email(email, None)
            user = User(
                id=self._store.next_id(),
                username=username,
                email=email,
                role=role,
                created_at=self._store.now(),
            )
            self._store.users[user.id] = user
            return _clone(user)

    def get_user(self, user_id):
        with self._lock:
            return _clone(self._user_or_raise(user_id))

    def list_users(self):
        with self._lock:
            users = sorted(self._store.users.values(), key=lambda u: u.id)
            return [_clone(u) for u in users]

    def update_user(self, user_id, username=None, email=None, role=None):
        with self._lock:
            user = self._user_or_raise(user_id)
            if username is not None:
                if _is_blank(username):
                    raise ValidationError("username must not be empty")
                username = username.strip()
                self._ensure_unique_username(username, user_id)
            if email is not None:
                if not _valid_email(email):
                    raise ValidationError("invalid email address")
                email = email.strip()
                self._ensure_unique_email(email, user_id)
            if role is not None and not isinstance(role, UserRole):
                raise ValidationError("role must be a UserRole")

            if username is not None:
                user.username = username
            if email is not None:
                user.email = email
            if role is not None:
                user.role = role
            return _clone(user)

    def delete_user(self, user_id):
        with self._lock:
            self._user_or_raise(user_id)
            for project in self._store.projects.values():
                if project.owner_id == user_id:
                    raise ConflictError(
                        "user owns project {0}".format(project.id)
                    )
            for task in self._store.tasks.values():
                if (
                    task.assignee_id == user_id
                    and task.status != TaskStatus.COMPLETED
                ):
                    raise ConflictError(
                        "user has open task {0}".format(task.id)
                    )
            del self._store.users[user_id]

    # -- internal helpers --------------------------------------------------
    def _ensure_unique_username(self, username, exclude_id):
        for other in self._store.users.values():
            if other.id == exclude_id:
                continue
            if other.username == username:
                raise DuplicateError(
                    "username {0!r} already in use".format(username)
                )

    def _ensure_unique_email(self, email, exclude_id):
        for other in self._store.users.values():
            if other.id == exclude_id:
                continue
            if other.email == email:
                raise DuplicateError(
                    "email {0!r} already in use".format(email)
                )


# ---------------------------------------------------------------------------
# Project service
# ---------------------------------------------------------------------------
class _ProjectService(_Service):
    def create_project(
        self, name, start_date, end_date, owner_id, description=""
    ):
        with self._lock:
            if _is_blank(name):
                raise ValidationError("project name must not be empty")
            if start_date is None or end_date is None:
                raise ValidationError("start and end dates are required")
            if end_date < start_date:
                raise ValidationError("end_date must not precede start_date")
            self._user_or_raise(owner_id)
            project = Project(
                id=self._store.next_id(),
                name=name.strip(),
                description=description or "",
                start_date=start_date,
                end_date=end_date,
                owner_id=owner_id,
                created_at=self._store.now(),
            )
            self._store.projects[project.id] = project
            return _clone(project)

    def get_project(self, project_id):
        with self._lock:
            return _clone(self._project_or_raise(project_id))

    def list_projects(self):
        with self._lock:
            projects = sorted(
                self._store.projects.values(), key=lambda p: p.id
            )
            return [_clone(p) for p in projects]

    def update_project(
        self,
        project_id,
        name=None,
        start_date=None,
        end_date=None,
        description=None,
    ):
        with self._lock:
            project = self._project_or_raise(project_id)
            new_start = project.start_date if start_date is None else start_date
            new_end = project.end_date if end_date is None else end_date
            if name is not None and _is_blank(name):
                raise ValidationError("project name must not be empty")
            if new_end < new_start:
                raise ValidationError("end_date must not precede start_date")

            if name is not None:
                project.name = name.strip()
            if start_date is not None:
                project.start_date = start_date
            if end_date is not None:
                project.end_date = end_date
            if description is not None:
                project.description = description
            return _clone(project)

    def delete_project(self, project_id):
        with self._lock:
            self._project_or_raise(project_id)
            doomed_tasks = [
                t.id
                for t in self._store.tasks.values()
                if t.project_id == project_id
            ]
            for task_id in doomed_tasks:
                del self._store.tasks[task_id]
            doomed_messages = [
                m.id
                for m in self._store.messages.values()
                if m.project_id == project_id or m.task_id in doomed_tasks
            ]
            for message_id in doomed_messages:
                del self._store.messages[message_id]
            del self._store.projects[project_id]


# ---------------------------------------------------------------------------
# Task service
# ---------------------------------------------------------------------------
class _TaskService(_Service):
    def create_task(self, project_id, title, assignee_id=None, deadline=None):
        with self._lock:
            project = self._project_or_raise(project_id)
            if _is_blank(title):
                raise ValidationError("task title must not be empty")
            if assignee_id is not None:
                self._user_or_raise(assignee_id)
            if deadline is not None and deadline < project.start_date:
                raise ValidationError(
                    "deadline must not precede project start"
                )
            task = Task(
                id=self._store.next_id(),
                project_id=project_id,
                title=title.strip(),
                status=TaskStatus.NOT_STARTED,
                assignee_id=assignee_id,
                deadline=deadline,
                started_at=None,
                completed_at=None,
                created_at=self._store.now(),
            )
            self._store.tasks[task.id] = task
            return _clone(task)

    def get_task(self, task_id):
        with self._lock:
            return _clone(self._task_or_raise(task_id))

    def list_tasks_by_project(self, project_id):
        with self._lock:
            self._project_or_raise(project_id)
            tasks = [
                t
                for t in self._store.tasks.values()
                if t.project_id == project_id
            ]
            tasks.sort(key=lambda t: t.id)
            return [_clone(t) for t in tasks]

    def list_tasks_by_assignee(self, assignee_id):
        with self._lock:
            self._user_or_raise(assignee_id)
            tasks = [
                t
                for t in self._store.tasks.values()
                if t.assignee_id == assignee_id
            ]
            tasks.sort(key=lambda t: t.id)
            return [_clone(t) for t in tasks]

    def assign_task(self, task_id, assignee_id):
        with self._lock:
            task = self._task_or_raise(task_id)
            self._user_or_raise(assignee_id)
            task.assignee_id = assignee_id
            return _clone(task)

    def reassign_task(self, task_id, new_assignee_id):
        with self._lock:
            task = self._task_or_raise(task_id)
            self._user_or_raise(new_assignee_id)
            task.assignee_id = new_assignee_id
            return _clone(task)

    def unassign_task(self, task_id):
        with self._lock:
            task = self._task_or_raise(task_id)
            task.assignee_id = None
            return _clone(task)

    def set_deadline(self, task_id, deadline):
        with self._lock:
            task = self._task_or_raise(task_id)
            if deadline is not None:
                project = self._store.projects.get(task.project_id)
                if project is not None and deadline < project.start_date:
                    raise ValidationError(
                        "deadline must not precede project start"
                    )
            task.deadline = deadline
            return _clone(task)

    def update_status(self, task_id, status):
        with self._lock:
            task = self._task_or_raise(task_id)
            if not isinstance(status, TaskStatus):
                raise ValidationError("status must be a TaskStatus")
            now = self._store.now()
            if status == TaskStatus.IN_PROGRESS:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = None
            elif status == TaskStatus.COMPLETED:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = now
            else:  # NOT_STARTED
                task.started_at = None
                task.completed_at = None
            task.status = status
            return _clone(task)


# ---------------------------------------------------------------------------
# Message service
# ---------------------------------------------------------------------------
class _MessageService(_Service):
    def post_message(
        self,
        author_id,
        body,
        project_id=None,
        task_id=None,
        attachments=None,
        parent_id=None,
    ):
        with self._lock:
            if (project_id is None) == (task_id is None):
                raise ValidationError(
                    "exactly one of project_id or task_id is required"
                )
            attachment_specs = list(attachments) if attachments else []
            if _is_blank(body) and not attachment_specs:
                raise ValidationError(
                    "message body must not be empty without attachments"
                )
            self._user_or_raise(author_id)
            if project_id is not None:
                self._project_or_raise(project_id)
            if task_id is not None:
                self._task_or_raise(task_id)
            if parent_id is not None:
                self._message_or_raise(parent_id)

            now = self._store.now()
            built = [
                self._build_attachment(filename, data, author_id, now)
                for filename, data in attachment_specs
            ]
            message = Message(
                id=self._store.next_id(),
                author_id=author_id,
                body=body,
                project_id=project_id,
                task_id=task_id,
                parent_id=parent_id,
                attachments=built,
                created_at=now,
                edited_at=None,
            )
            self._store.messages[message.id] = message
            return _clone(message)

    def edit_message(self, message_id, editor_id, new_body):
        with self._lock:
            message = self._message_or_raise(message_id)
            if message.author_id != editor_id:
                raise AuthorizationError("only the author may edit a message")
            if _is_blank(new_body):
                raise ValidationError("message body must not be empty")
            message.body = new_body
            message.edited_at = self._store.now()
            return _clone(message)

    def add_attachment(self, message_id, user_id, filename, data):
        with self._lock:
            message = self._message_or_raise(message_id)
            if message.author_id != user_id:
                raise AuthorizationError(
                    "only the author may attach to a message"
                )
            if _is_blank(filename):
                raise ValidationError("filename must not be empty")
            attachment = self._build_attachment(
                filename, data, user_id, self._store.now()
            )
            message.attachments.append(attachment)
            return _clone(message)

    def list_messages_by_project(self, project_id):
        with self._lock:
            self._project_or_raise(project_id)
            messages = [
                m
                for m in self._store.messages.values()
                if m.project_id == project_id
            ]
            messages.sort(key=lambda m: m.id)
            return [_clone(m) for m in messages]

    def list_messages_by_task(self, task_id):
        with self._lock:
            self._task_or_raise(task_id)
            messages = [
                m
                for m in self._store.messages.values()
                if m.task_id == task_id
            ]
            messages.sort(key=lambda m: m.id)
            return [_clone(m) for m in messages]

    def delete_message(self, message_id, user_id):
        with self._lock:
            message = self._message_or_raise(message_id)
            if message.author_id != user_id:
                raise AuthorizationError(
                    "only the author may delete a message"
                )
            del self._store.messages[message_id]

    # -- internal helpers --------------------------------------------------
    def _build_attachment(self, filename, data, uploaded_by, uploaded_at):
        if _is_blank(filename):
            raise ValidationError("filename must not be empty")
        size = len(data) if data is not None else 0
        return Attachment(
            filename=filename,
            size=size,
            uploaded_by=uploaded_by,
            uploaded_at=uploaded_at,
        )


# ---------------------------------------------------------------------------
# Performance service
# ---------------------------------------------------------------------------
class _PerformanceService(_Service):
    def _tasks_for(self, user_id):
        return [
            t
            for t in self._store.tasks.values()
            if t.assignee_id == user_id
        ]

    def get_completion_rate(self, user_id):
        with self._lock:
            self._user_or_raise(user_id)
            return _task_metrics(self._tasks_for(user_id))["completion_rate"]

    def get_average_completion_time(self, user_id):
        with self._lock:
            self._user_or_raise(user_id)
            return _task_metrics(self._tasks_for(user_id))[
                "average_completion_time"
            ]

    def submit_rating(
        self, rater_id, ratee_id, score, feedback="", task_id=None
    ):
        with self._lock:
            self._user_or_raise(rater_id)
            self._user_or_raise(ratee_id)
            if rater_id == ratee_id:
                raise ConflictError("users may not rate themselves")
            if not isinstance(score, int) or isinstance(score, bool):
                raise ValidationError("score must be an integer 1-5")
            if score < 1 or score > 5:
                raise ValidationError("score must be between 1 and 5")
            if task_id is not None:
                self._task_or_raise(task_id)
            rating = Rating(
                id=self._store.next_id(),
                rater_id=rater_id,
                ratee_id=ratee_id,
                score=score,
                feedback=feedback or "",
                task_id=task_id,
                created_at=self._store.now(),
            )
            self._store.ratings[rating.id] = rating
            return _clone(rating)

    def _ratings_for(self, user_id):
        ratings = [
            r
            for r in self._store.ratings.values()
            if r.ratee_id == user_id
        ]
        ratings.sort(key=lambda r: r.id)
        return ratings

    def get_ratings_summary(self, user_id):
        with self._lock:
            self._user_or_raise(user_id)
            ratings = self._ratings_for(user_id)
            count = len(ratings)
            average = (
                sum(r.score for r in ratings) / float(count) if count else 0.0
            )
            return {
                "count": count,
                "average": average,
                "ratings": [_clone(r) for r in ratings],
            }

    def get_user_dashboard(self, user_id):
        with self._lock:
            self._user_or_raise(user_id)
            metrics = _task_metrics(self._tasks_for(user_id))
            ratings = self._ratings_for(user_id)
            count = len(ratings)
            average = (
                sum(r.score for r in ratings) / float(count) if count else 0.0
            )
            return {
                "user_id": user_id,
                "total_tasks": metrics["total_tasks"],
                "completed_tasks": metrics["completed_tasks"],
                "in_progress_tasks": metrics["in_progress_tasks"],
                "not_started_tasks": metrics["not_started_tasks"],
                "completion_rate": metrics["completion_rate"],
                "average_completion_time": metrics["average_completion_time"],
                "rating_count": count,
                "rating_average": average,
            }


# ---------------------------------------------------------------------------
# Report service
# ---------------------------------------------------------------------------
class _ReportService(_Service):
    def project_progress_report(self, project_id):
        with self._lock:
            self._project_or_raise(project_id)
            tasks = [
                t
                for t in self._store.tasks.values()
                if t.project_id == project_id
            ]
            status_counts = dict((s.value, 0) for s in TaskStatus)
            for task in tasks:
                status_counts[task.status.value] += 1
            total = len(tasks)
            completed = status_counts[TaskStatus.COMPLETED.value]
            completion_rate = (float(completed) / total) if total else 0.0
            now = self._store.now()
            overdue = 0
            per_assignee = {}
            for task in tasks:
                if (
                    task.deadline is not None
                    and task.deadline < now
                    and task.status != TaskStatus.COMPLETED
                ):
                    overdue += 1
                if task.assignee_id is not None:
                    bucket = per_assignee.setdefault(
                        task.assignee_id,
                        {"total_tasks": 0, "completed_tasks": 0},
                    )
                    bucket["total_tasks"] += 1
                    if task.status == TaskStatus.COMPLETED:
                        bucket["completed_tasks"] += 1
            return {
                "report_type": ReportType.PROJECT_PROGRESS.value,
                "project_id": project_id,
                "total_tasks": total,
                "status_counts": status_counts,
                "completion_rate": completion_rate,
                "overdue_tasks": overdue,
                "per_assignee": per_assignee,
            }

    def team_performance_report(self, project_id=None):
        with self._lock:
            if project_id is not None:
                self._project_or_raise(project_id)
                tasks = [
                    t
                    for t in self._store.tasks.values()
                    if t.project_id == project_id
                ]
            else:
                tasks = list(self._store.tasks.values())

            by_user = {}
            for task in tasks:
                if task.assignee_id is not None:
                    by_user.setdefault(task.assignee_id, []).append(task)

            rows = []
            for user_id in sorted(by_user):
                metrics = _task_metrics(by_user[user_id])
                user = self._store.users.get(user_id)
                row = {
                    "user_id": user_id,
                    "username": user.username if user else None,
                }
                row.update(metrics)
                rows.append(row)
            return {
                "report_type": ReportType.TEAM_PERFORMANCE.value,
                "project_id": project_id,
                "rows": rows,
            }

    def individual_performance_report(self, user_id):
        with self._lock:
            self._user_or_raise(user_id)
            tasks = [
                t
                for t in self._store.tasks.values()
                if t.assignee_id == user_id
            ]
            tasks.sort(key=lambda t: t.id)
            metrics = _task_metrics(tasks)
            task_rows = [
                {
                    "task_id": t.id,
                    "title": t.title,
                    "status": t.status.value,
                    "deadline": t.deadline,
                    "started_at": t.started_at,
                    "completed_at": t.completed_at,
                }
                for t in tasks
            ]
            report = {
                "report_type": ReportType.INDIVIDUAL_PERFORMANCE.value,
                "user_id": user_id,
            }
            report.update(metrics)
            report["tasks"] = task_rows
            return report

    def export_report(self, report, report_format):
        with self._lock:
            if not isinstance(report, dict):
                raise ValidationError("report must be a dict")
            if not isinstance(report_format, ReportFormat):
                raise ValidationError("report_format must be a ReportFormat")
            if report_format == ReportFormat.CSV:
                return self._to_csv(report)
            return self._to_pdf(report)

    # -- serialization helpers --------------------------------------------
    def _to_csv(self, report):
        buffer = io.StringIO()
        writer = csv.writer(buffer)
        rows = report.get("rows")
        if isinstance(rows, list):
            keys = []
            for row in rows:
                if isinstance(row, dict):
                    for key in row.keys():
                        if key not in keys:
                            keys.append(key)
            if not keys:
                keys = [k for k in report.keys() if k != "rows"]
            writer.writerow(keys)
            for row in rows:
                writer.writerow(
                    [_scalar(row.get(k)) for k in keys]
                    if isinstance(row, dict)
                    else [_scalar(row)]
                )
        else:
            flat = self._flatten(report)
            writer.writerow(list(flat.keys()))
            writer.writerow([_scalar(v) for v in flat.values()])
        return buffer.getvalue()

    def _flatten(self, report):
        flat = {}
        for key, value in report.items():
            if isinstance(value, dict):
                if not value:
                    continue
                for sub_key, sub_value in value.items():
                    flat["{0}.{1}".format(key, sub_key)] = sub_value
            elif isinstance(value, (list, tuple)):
                flat[key] = len(value)
            else:
                flat[key] = value
        return flat

    def _to_pdf(self, report):
        return _build_pdf(_report_to_lines(report))


# ---------------------------------------------------------------------------
# PDF rendering (minimal, self-contained, valid header)
# ---------------------------------------------------------------------------
def _pdf_escape(text):
    return (
        text.replace("\\", "\\\\").replace("(", "\\(").replace(")", "\\)")
    )


def _report_to_lines(report):
    lines = []
    lines.append("Report: {0}".format(report.get("report_type", "report")))
    for key, value in report.items():
        if key == "report_type":
            continue
        if isinstance(value, (list, tuple)):
            lines.append("{0}: {1} item(s)".format(key, len(value)))
            for item in list(value)[:100]:
                if isinstance(item, dict):
                    rendered = ", ".join(
                        "{0}={1}".format(k, _scalar(v))
                        for k, v in item.items()
                    )
                else:
                    rendered = _scalar(item)
                lines.append("  - {0}".format(rendered))
        elif isinstance(value, dict):
            lines.append("{0}:".format(key))
            for sub_key, sub_value in value.items():
                lines.append(
                    "  {0}: {1}".format(sub_key, _scalar(sub_value))
                )
        else:
            lines.append("{0}: {1}".format(key, _scalar(value)))
    return lines


def _build_pdf(lines):
    """Build a minimal but structurally valid single-page PDF document."""

    content_parts = ["BT", "/F1 12 Tf", "50 760 Td", "14 TL"]
    rendered = lines if lines else [""]
    first = True
    for line in rendered:
        text = _pdf_escape(line)
        if first:
            content_parts.append("({0}) Tj".format(text))
            first = False
        else:
            content_parts.append("T*")
            content_parts.append("({0}) Tj".format(text))
    content_parts.append("ET")
    content = "\n".join(content_parts).encode("latin-1", "replace")

    objects = [
        b"<< /Type /Catalog /Pages 2 0 R >>",
        b"<< /Type /Pages /Kids [3 0 R] /Count 1 >>",
        (
            b"<< /Type /Page /Parent 2 0 R /MediaBox [0 0 612 792] "
            b"/Contents 4 0 R /Resources << /Font << /F1 5 0 R >> >> >>"
        ),
        b"<< /Length "
        + str(len(content)).encode("latin-1")
        + b" >>\nstream\n"
        + content
        + b"\nendstream",
        b"<< /Type /Font /Subtype /Type1 /BaseFont /Helvetica >>",
    ]

    pdf = bytearray()
    pdf += b"%PDF-1.4\n"
    offsets = []
    for index, body in enumerate(objects, start=1):
        offsets.append(len(pdf))
        pdf += "{0} 0 obj\n".format(index).encode("latin-1")
        pdf += body
        pdf += b"\nendobj\n"

    xref_pos = len(pdf)
    size = len(objects) + 1
    pdf += "xref\n0 {0}\n".format(size).encode("latin-1")
    pdf += b"0000000000 65535 f \n"
    for offset in offsets:
        pdf += "{0:010d} 00000 n \n".format(offset).encode("latin-1")
    pdf += (
        "trailer\n<< /Size {0} /Root 1 0 R >>\nstartxref\n{1}\n%%EOF\n".format(
            size, xref_pos
        ).encode("latin-1")
    )
    return bytes(pdf)


